<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,sans-serif;margin:0;padding:20px;background:#f4f6fa;}
  .board{display:flex;gap:15px;}
  .column{background:white;border-radius:5px;flex:1;display:flex;flex-direction:column;height:80vh;}
  .header{padding:10px;font-weight:bold;background:#e0e3e8;border-bottom:1px solid #d0d4da;}
  .count{float:right;color:#555;}
  .cards{flex:1;padding:10px;overflow-y:auto;}
  .card{background:#fff;border-radius:5px;padding:10px;margin-bottom:8px;box-shadow:0 1px 3px rgba(0,0,0,.1);display:flex;justify-content:space-between;align-items:center;}
  .card-del{background:none;border:none;color:red;font-weight:bold;cursor:pointer;}
  #new-card{width:100%;padding:8px;margin-bottom:10px;border:1px solid #ccc;border-radius:3px;}
  #add-card{padding:8px 12px;background:#28a745;color:white;border:none;border-radius:3px;cursor:pointer;}
</style>
</head>
<body>

<h2>Kanban Board</h2>
<input type="text" id="new-card" placeholder="New task title">
<button id="add-card">Add Card</button>

<div class="board">
  <div id="col-todo" class="column" data-col="todo">
    <div class="header">To Do <span class="count"></span></div>
    <div class="cards" ondragover="allowDrop(event)" ondrop="dropCard(event)"></div>
  </div>
  <div id="col-doing" class="column" data-col="doing">
    <div class="header">Doing <span class="count"></span></div>
    <div class="cards" ondragover="allowDrop(event)" ondrop="dropCard(event)"></div>
  </div>
  <div id="col-done" class="column" data-col="done">
    <div class="header">Done <span class="count"></span></div>
    <div class="cards" ondragover="allowDrop(event)" ondrop="dropCard(event)"></div>
  </div>
</div>

<script>
const STORAGE_KEY = 'kanbanState';
let state = []; // [{id, title, column}]
let idCounter = 0;

// Load from localStorage
function loadState() {
  const data = localStorage.getItem(STORAGE_KEY);
  if (data) {
    try { state = JSON.parse(data); }
    catch(e){ state=[]; }
    // Update idCounter to avoid duplicates
    idCounter = state.reduce((max, c)=> Math.max(max, parseInt(c.id)), 0)+1;
  } else state=[];
}

// Save to localStorage
function saveState() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

// Render entire board
function renderBoard() {
  ['todo','doing','done'].forEach(col=>{
    const container = document.querySelector(`#col-${col} .cards`);
    container.innerHTML='';
    state.filter(c=>c.column===col).forEach(card=>container.appendChild(createCardElement(card)));
    updateCount(col);
  });
}

// Create card DOM element
function createCardElement(card) {
  const el=document.createElement('div');
  el.className='card';
  el.setAttribute('draggable','true');
  el.dataset.id=card.id;
  el.addEventListener('dragstart', dragStart);

  const titleSpan=document.createElement('span');
  titleSpan.textContent=card.title;

  const delBtn=document.createElement('button');
  delBtn.className='card-del';
  delBtn.innerHTML='✕';
  delBtn.onclick=()=>deleteCard(card.id);

  el.appendChild(titleSpan);
  el.appendChild(delBtn);
  return el;
}

// Update count display
function updateCount(col) {
  const cnt=document.querySelector(`#col-${col} .count`);
  cnt.textContent=`(${state.filter(c=>c.column===col).length})`;
}

// Add new card
document.getElementById('add-card').onclick=()=>{
  const input=document.getElementById('new-card');
  const title=input.value.trim();
  if(!title)return;
  const id=idCounter++;
  state.push({id:id.toString(), title, column:'todo'});
  saveState();
  renderBoard();
  input.value='';
};

// Delete card
function deleteCard(id) {
  state = state.filter(c=>c.id!==id);
  saveState();
  renderBoard();
}

// Drag & Drop handlers
function dragStart(e){
  e.dataTransfer.setData('text/plain', e.target.dataset.id);
}
function allowDrop(e){e.preventDefault();}
function dropCard(e){
  e.preventDefault();
  const id=e.dataTransfer.getData('text/plain');
  const targetCol = e.currentTarget.parentElement.dataset.col;
  moveCard(id, targetCol);
}

// Move card to new column
function moveCard(id, newCol) {
  const card=state.find(c=>c.id===id);
  if(card && card.column!==newCol){
    card.column=newCol;
    saveState();
    renderBoard();
  }
}

// Initialize
loadState();
renderBoard();
</script>
</body>
</html>
